,p_plug_template=>2100526641005906379
,p_plug_display_sequence=>20
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT h.typzmiany,',
'       h.datarozpoczecia,',
'       h.zadanie,',
'       p.imie || '' '' || p.nazwisko as pracownik,',
'       p.stanowisko',
'FROM pracownik p',
'JOIN harmonogrampracownika h ON p.pracownikid = h.pracownikid',
'WHERE h.typzmiany = :P4_ZMIANA OR :P4_ZMIANA IS NULL'))
,p_plug_source_type=>'NATIVE_IR'
,p_ajax_items_to_submit=>'P4_ZMIANA'
