,p_validation_name=>unistr('Sprawd\017A Klienta')
,p_validation_sequence=>10
,p_validation=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'  v_count NUMBER;',
'BEGIN',
'  -- 1. Czy to liczba?',
'  IF NOT REGEXP_LIKE(:P_KLIENT_ID, ''^[0-9]+$'') THEN',
unistr('     RETURN ''ID Klienta musi by\0107 liczb\0105!'';'),
'  END IF;',
'',
'  -- 2. Czy istnieje w bazie?',
'  SELECT count(*) INTO v_count FROM klient WHERE klientid = :P_KLIENT_ID;',
'',
'  IF v_count = 0 THEN',
'     RETURN ''Nie ma takiego klienta w bazie!'';',
'  END IF;',
'',
'  RETURN NULL;',
'END;'))
,p_validation2=>'PLSQL'
,p_validation_type=>'FUNC_BODY_RETURNING_ERR_TEXT'
,p_associated_item=>wwv_flow_imp.id(127827993830573019203)
,p_error_display_location=>'INLINE_WITH_FIELD_AND_NOTIFICATION'
);
